package com.bbblllllocck.canned_emotions.ui.features.databaseScreen

import androidx.compose.foundation.layout.Arrangement
import androidx.compose.foundation.layout.Column
import androidx.compose.foundation.layout.Row
import androidx.compose.foundation.layout.fillMaxHeight
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.foundation.layout.fillMaxWidth
import androidx.compose.foundation.layout.padding
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material3.Card
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.runtime.DisposableEffect
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.remember
import androidx.compose.runtime.setValue
import androidx.compose.ui.Modifier
import androidx.compose.ui.text.style.TextOverflow
import androidx.compose.ui.unit.dp
import com.bbblllllocck.canned_emotions.core.database.objectboxFunctions.DatabaseManager
import com.bbblllllocck.canned_emotions.core.database.objectboxFunctions.MusicScanTaskEntity
import com.bbblllllocck.canned_emotions.core.database.objectboxFunctions.MusicScanTaskEntity_
import io.objectbox.android.AndroidScheduler

@Composable
fun DatabaseScreen() {
	var allTasks by remember { mutableStateOf(emptyList<MusicScanTaskEntity>()) }

	DisposableEffect(Unit) {
		val box = DatabaseManager.musicTaskBox()
		val query = box.query()
			.orderDesc(MusicScanTaskEntity_.updatedAtMillis)
			.build()

		allTasks = query.find()

		val subscription = query.subscribe()
			.on(AndroidScheduler.mainThread())
			.observer { tasks ->
				allTasks = tasks.orEmpty()
			}

		onDispose {
			subscription.cancel()
			query.close()
		}
	}

	val processed = allTasks.filter { it.status == MusicScanTaskEntity.DONE }
	val unprocessed = allTasks.filter { it.status != MusicScanTaskEntity.DONE }

	Column(
		modifier = Modifier
			.fillMaxSize()
			.padding(16.dp),
		verticalArrangement = Arrangement.spacedBy(12.dp)
	) {
		Text(
			text = "数据库任务 (${allTasks.size})",
			style = MaterialTheme.typography.titleLarge
		)

		Row(
			modifier = Modifier.fillMaxSize(),
			horizontalArrangement = Arrangement.spacedBy(12.dp)
		) {
			TaskColumn(
				title = "未处理 (${unprocessed.size})",
				tasks = unprocessed,
				modifier = Modifier
					.weight(1f)
					.fillMaxHeight()
			)
			TaskColumn(
				title = "已处理 (${processed.size})",
				tasks = processed,
				modifier = Modifier
					.weight(1f)
					.fillMaxHeight()
			)
		}
	}
}

@Composable
private fun TaskColumn(
	title: String,
	tasks: List<MusicScanTaskEntity>,
	modifier: Modifier = Modifier
) {
	Card(modifier = modifier) {
		Column(
			modifier = Modifier
				.fillMaxSize()
				.padding(10.dp),
			verticalArrangement = Arrangement.spacedBy(8.dp)
		) {
			Text(text = title, style = MaterialTheme.typography.titleMedium)
			LazyColumn(
				modifier = Modifier.fillMaxSize(),
				verticalArrangement = Arrangement.spacedBy(6.dp)
			) {
				items(tasks, key = { it.id }) { task ->
					TaskItem(task = task)
				}
			}
		}
	}
}

@Composable
private fun TaskItem(task: MusicScanTaskEntity) {
	Card(modifier = Modifier.fillMaxWidth()) {
		Column(
			modifier = Modifier
				.fillMaxWidth()
				.padding(10.dp),
			verticalArrangement = Arrangement.spacedBy(3.dp)
		) {
			Text(
				text = task.title.ifBlank { "(无标题)" },
				style = MaterialTheme.typography.bodyLarge,
				maxLines = 1,
				overflow = TextOverflow.Ellipsis
			)
			Text(
				text = "${task.artist.ifBlank { "未知艺术家" }} - ${task.album.ifBlank { "未知专辑" }}",
				style = MaterialTheme.typography.bodySmall,
				maxLines = 1,
				overflow = TextOverflow.Ellipsis
			)
			Text(
				text = statusLabel(task.status),
				style = MaterialTheme.typography.labelSmall
			)
		}
	}
}

private fun statusLabel(status: Int): String {
	return when (status) {
		MusicScanTaskEntity.PENDING -> "状态: PENDING(待处理)"
		MusicScanTaskEntity.DONE -> "状态: DONE(已处理)"
		MusicScanTaskEntity.UNEXIST -> "状态: UNEXIST(文件不存在)"
		else -> "状态: UNKNOWN($status)"
	}
}

package com.bbblllllocck.canned_emotions.ui.features.databaseScreen

import androidx.compose.foundation.layout.Arrangement
import androidx.compose.foundation.layout.Column
import androidx.compose.foundation.layout.Row
import androidx.compose.foundation.layout.fillMaxHeight
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.foundation.layout.fillMaxWidth
import androidx.compose.foundation.layout.padding
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material3.Button
import androidx.compose.material3.Card
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.runtime.DisposableEffect
import androidx.compose.runtime.LaunchedEffect
import androidx.compose.runtime.collectAsState
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.remember
import androidx.compose.runtime.setValue
import androidx.compose.ui.Modifier
import androidx.compose.ui.text.style.TextOverflow
import androidx.compose.ui.unit.dp
import com.bbblllllocck.canned_emotions.core.database.DatabaseVectorStorgeTaskLogic
import com.bbblllllocck.canned_emotions.core.database.objectboxFunctions.DatabaseManager
import com.bbblllllocck.canned_emotions.core.database.objectboxFunctions.MusicScanTaskEntity
import com.bbblllllocck.canned_emotions.core.database.objectboxFunctions.MusicScanTaskEntity_
import io.objectbox.android.AndroidScheduler

@Composable
fun DatabaseScreen() {
    var allTasks by remember { mutableStateOf(emptyList<MusicScanTaskEntity>()) }
    val queueState by DatabaseVectorStorgeTaskLogic.state.collectAsState()

    LaunchedEffect(Unit) {
        DatabaseVectorStorgeTaskLogic.refreshSnapshot()
    }

    DisposableEffect(Unit) {
        val box = DatabaseManager.musicTaskBox()
        val query = box.query()
            .orderDesc(MusicScanTaskEntity_.updatedAtMillis)
            .build()

        allTasks = query.find()

        val subscription = query.subscribe()
            .on(AndroidScheduler.mainThread())
            .observer { tasks ->
                allTasks = tasks.orEmpty()
            }

        onDispose {
            subscription.cancel()
            query.close()
        }
    }

    val processed = allTasks.filter { it.status == MusicScanTaskEntity.DONE }
    val unprocessed = allTasks.filter { it.status != MusicScanTaskEntity.DONE }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        Text(
            text = "数据库任务 (${allTasks.size})",
            style = MaterialTheme.typography.titleLarge
        )

        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Button(
                onClick = { DatabaseVectorStorgeTaskLogic.start() },
                enabled = !queueState.isRunning,
                modifier = Modifier.weight(1f)
            ) {
                Text("开始向量队列")
            }

            Button(
                onClick = { DatabaseVectorStorgeTaskLogic.pause() },
                enabled = queueState.isRunning,
                modifier = Modifier.weight(1f)
            ) {
                Text("暂停向量队列")
            }
        }

        Text(
            text = "队列状态: ${if (queueState.isRunning) "运行中" else "已暂停"} | 待处理 ${queueState.pendingCount} | 已完成 ${queueState.doneCount}",
            style = MaterialTheme.typography.bodyMedium
        )

        if (queueState.currentTaskTitle.isNotBlank()) {
            Text(
                text = "当前任务: ${queueState.currentTaskTitle}",
                style = MaterialTheme.typography.bodySmall,
                maxLines = 1,
                overflow = TextOverflow.Ellipsis
            )
        }

        Text(
            text = queueState.statusMessage,
            style = MaterialTheme.typography.bodySmall
        )

        Row(
            modifier = Modifier.fillMaxSize(),
            horizontalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            TaskColumn(
                title = "未处理 (${unprocessed.size})",
                tasks = unprocessed,
                modifier = Modifier
                    .weight(1f)
                    .fillMaxHeight()
            )
            TaskColumn(
                title = "已处理 (${processed.size})",
                tasks = processed,
                modifier = Modifier
                    .weight(1f)
                    .fillMaxHeight()
            )
        }
    }
}

@Composable
private fun TaskColumn(
    title: String,
    tasks: List<MusicScanTaskEntity>,
    modifier: Modifier = Modifier
) {
    Card(modifier = modifier) {
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(10.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Text(text = title, style = MaterialTheme.typography.titleMedium)
            LazyColumn(
                modifier = Modifier.fillMaxSize(),
                verticalArrangement = Arrangement.spacedBy(6.dp)
            ) {
                items(tasks, key = { it.id }) { task ->
                    TaskItem(task = task)
                }
            }
        }
    }
}

@Composable
private fun TaskItem(task: MusicScanTaskEntity) {
    Card(modifier = Modifier.fillMaxWidth()) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(10.dp),
            verticalArrangement = Arrangement.spacedBy(3.dp)
        ) {
            Text(
                text = task.title.ifBlank { "(无标题)" },
                style = MaterialTheme.typography.bodyLarge,
                maxLines = 1,
                overflow = TextOverflow.Ellipsis
            )
            Text(
                text = "${task.artist.ifBlank { "未知艺术家" }} - ${task.album.ifBlank { "未知专辑" }}",
                style = MaterialTheme.typography.bodySmall,
                maxLines = 1,
                overflow = TextOverflow.Ellipsis
            )
            Text(
                text = statusLabel(task.status),
                style = MaterialTheme.typography.labelSmall
            )
        }
    }
}

private fun statusLabel(status: Int): String {
    return when (status) {
        MusicScanTaskEntity.PENDING -> "状态: PENDING(待处理)"
        MusicScanTaskEntity.DONE -> "状态: DONE(已处理)"
        MusicScanTaskEntity.UNEXIST -> "状态: UNEXIST(文件不存在)"
        else -> "状态: UNKNOWN($status)"
    }
}

package com.bbblllllocck.canned_emotions.core.database.geminiRequestCall

import android.content.Context
import android.net.Uri
import android.os.Looper
import android.util.Log
import androidx.core.net.toUri
import com.bbblllllocck.canned_emotions.core.api.AppContextProvider
import com.google.genai.types.Blob
import com.google.genai.types.Content
import com.google.genai.types.EmbedContentConfig
import com.google.genai.types.Part
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.sync.Semaphore
import kotlinx.coroutines.sync.withPermit
import kotlinx.coroutines.withContext
import java.io.File
import java.lang.reflect.InvocationHandler
import java.lang.reflect.Proxy
import java.util.Optional
import java.util.concurrent.CountDownLatch
import java.util.concurrent.TimeUnit

private const val MAX_AUDIO_DURATION_MS = 80_000L
private const val LOG_TAG = "EmbeddingCall"
private const val TRANSCODE_TIMEOUT_MS = 20_000L

// 只限制请求层并发，避免高峰时瞬间打爆上行和 API。
private val apiSemaphore = Semaphore(2)

private class PreparedAudio(
    val bytes: ByteArray,
    val mimeType: String,
    val tempFile: File? = null
)

object EmbeddingCall {

    /**
     * 唯一公开入口：传入数据库中的 filePath（content Uri 或绝对路径），返回 embedding 向量。
     */
    suspend fun process(audioRef: String, context: Context = AppContextProvider.get()): List<Float> {
        Log.i(LOG_TAG, "process start, ref=$audioRef")
        val prepared = withContext(Dispatchers.IO) {
            prepareAudio(context, audioRef)
        }

        return try {
            apiSemaphore.withPermit {
                ClientManager.executeWithRetry { healthyClient ->
                    Log.d(LOG_TAG, "embed request start, mime=${prepared.mimeType}, bytes=${prepared.bytes.size}")
                    val audioPart = Part.builder()
                        .inlineData(
                            Blob.builder()
                                .data(prepared.bytes)
                                .mimeType(prepared.mimeType)
                                .build()
                        )
                        .build()

                    val content = Content.builder()
                        .parts(listOf(audioPart))
                        .build()

                    val config = EmbedContentConfig.builder()
                        .outputDimensionality(768)
                        .taskType("RETRIEVAL_DOCUMENT")
                        .build()

                    val response = healthyClient.models.embedContent(
                        "gemini-embedding-2-preview",
                        content,
                        config
                    )

                    val rawEmbeddings = response.embeddings()
                    Log.d(LOG_TAG, "embeddings raw type=${rawEmbeddings?.javaClass?.name ?: "null"}")

                    val values = extractEmbeddingValues(rawEmbeddings)
                        ?: throw IllegalStateException(
                            "Gemini embedding empty, mime=${prepared.mimeType}, bytes=${prepared.bytes.size}, " +
                                    "rawType=${rawEmbeddings?.javaClass?.name ?: "null"}, " +
                                    "responseType=${response.javaClass.name}, responsePreview=${preview(response.toString())}"
                        )
                    Log.d(LOG_TAG, "embedding parsed, dims=${values.size}")
                    values
                }
            }
        } finally {
            Log.d(LOG_TAG, "process end, tempDeleted=${prepared.tempFile != null}")
            prepared.tempFile?.delete()
        }
    }

    private fun prepareAudio(context: Context, audioRef: String): PreparedAudio {
        val sourceUri = resolveUri(audioRef)
        Log.d(LOG_TAG, "prepareAudio source=$sourceUri")

        var transcodeError: Throwable? = null
        val aacFile = runCatching {
            transcodeToAacClip(context, sourceUri)
        }.onFailure {
            transcodeError = it
        }.getOrNull()

        if (aacFile != null && aacFile.exists()) {
            Log.d(LOG_TAG, "audio transcode success, upload mime=audio/mp4")
            return PreparedAudio(
                bytes = aacFile.readBytes(),
                mimeType = "audio/mp4",
                tempFile = aacFile
            )
        }

        val fallbackBytes = context.contentResolver.openInputStream(sourceUri)?.use { it.readBytes() }
            ?: throw IllegalStateException("无法读取音频: $audioRef")

        // 某些机型/源格式可能导致转码失败，这里保留兜底路径，避免任务直接中断。
        if (transcodeError != null) {
            Log.w(LOG_TAG, "audio transcode failed, fallback to source bytes", transcodeError)
        } else {
            Log.w(LOG_TAG, "audio transcode skipped, fallback to source bytes")
        }

        val fallbackMime = guessMimeType(sourceUri, audioRef)
        Log.d(LOG_TAG, "fallback mime=$fallbackMime")

        if (!isAllowedFallbackMime(fallbackMime)) {
            throw IllegalStateException(
                "AAC transcode failed and fallback mime is unsupported: $fallbackMime, ref=$audioRef"
            )
        }

        return PreparedAudio(
            bytes = fallbackBytes,
            mimeType = fallbackMime
        )
    }

    private fun transcodeToAacClip(context: Context, sourceUri: Uri): File {
        val outFile = File.createTempFile("embed_clip_", ".m4a", context.cacheDir)
        val latch = CountDownLatch(1)
        var exportError: Throwable? = null
        var completed = false

        val transformer = buildTransformer(context, latch) { error ->
            exportError = error
        }

        val mediaItem = buildClippedMediaItem(sourceUri)

        val started = startTransformation(transformer, mediaItem, outFile.absolutePath)
        if (!started) {
            throw IllegalStateException("Media3 Transformer start failed: no compatible start method found")
        }

        val finished = latch.await(TRANSCODE_TIMEOUT_MS, TimeUnit.MILLISECONDS)
        if (!finished) {
            cancelTransformation(transformer)
            throw IllegalStateException("Media3 Transformer timeout over ${TRANSCODE_TIMEOUT_MS}ms")
        }

        if (exportError != null) {
            throw IllegalStateException("Media3 Transformer export failed", exportError)
        }

        if (!completedByFile(outFile)) {
            if (exportError == null) {
                throw IllegalStateException("Media3 Transformer finished but output file is empty")
            }
            throw IllegalStateException("Media3 Transformer output invalid", exportError)
        }

        completed = true
        if (!completed) {
            throw IllegalStateException("Media3 Transformer completed flag not set")
        }

        Log.d(LOG_TAG, "transcode success (Media3 Transformer) -> ${outFile.absolutePath}")
        return outFile
    }

    private fun buildTransformer(
        context: Context,
        latch: CountDownLatch,
        onError: (Throwable) -> Unit
    ): Any {
        val builderClass = Class.forName("androidx.media3.transformer.Transformer\$Builder")
        val builder = builderClass.getConstructor(Context::class.java).newInstance(context)

        // Force main looper to avoid thread/looper related runtime issues.
        invokeSingleArgByName(builder, "setLooper", Looper.getMainLooper())

        val audioAacMime = runCatching {
            Class.forName("androidx.media3.common.MimeTypes")
                .getField("AUDIO_AAC")
                .get(null) as String
        }.getOrDefault("audio/mp4a-latm")

        val request = runCatching {
            val reqBuilderClass = Class.forName("androidx.media3.transformer.TransformationRequest\$Builder")
            val reqBuilder = reqBuilderClass.getConstructor().newInstance()
            invokeSingleArgByName(reqBuilder, "setAudioMimeType", audioAacMime)
            invokeNoArgByName(reqBuilder, "build")
        }.getOrNull()

        if (request != null) {
            invokeSingleArgByName(builder, "setTransformationRequest", request)
        }

        val listenerInterface = Class.forName("androidx.media3.transformer.Transformer\$Listener")
        val listener = Proxy.newProxyInstance(
            listenerInterface.classLoader,
            arrayOf(listenerInterface),
            InvocationHandler { _, method, args ->
                when {
                    method.name.contains("Completed", ignoreCase = true) -> {
                        latch.countDown()
                    }
                    method.name.contains("Error", ignoreCase = true) -> {
                        val throwable = args?.firstOrNull { it is Throwable } as? Throwable
                            ?: IllegalStateException("Transformer listener error without throwable")
                        onError(throwable)
                        latch.countDown()
                    }
                }
                null
            }
        )

        val listenerAttachedOnBuilder = invokeSingleArgByName(builder, "addListener", listener)
        val transformer = invokeNoArgByName(builder, "build")
            ?: throw IllegalStateException("Transformer builder.build() failed")

        if (!listenerAttachedOnBuilder) {
            invokeSingleArgByName(transformer, "addListener", listener)
        }

        return transformer
    }

    private fun buildClippedMediaItem(sourceUri: Uri): Any {
        val mediaItemClass = Class.forName("androidx.media3.common.MediaItem")
        val mediaItemBuilderClass = Class.forName("androidx.media3.common.MediaItem\$Builder")
        val clippingBuilderClass = Class.forName("androidx.media3.common.MediaItem\$ClippingConfiguration\$Builder")

        val clippingBuilder = clippingBuilderClass.getConstructor().newInstance()
        invokeSingleArgByName(clippingBuilder, "setEndPositionMs", MAX_AUDIO_DURATION_MS)
        val clipping = invokeNoArgByName(clippingBuilder, "build")
            ?: throw IllegalStateException("MediaItem clipping build failed")

        val mediaItemBuilder = mediaItemBuilderClass.getConstructor().newInstance()
        invokeSingleArgByName(mediaItemBuilder, "setUri", sourceUri)
        invokeSingleArgByName(mediaItemBuilder, "setClippingConfiguration", clipping)

        return invokeNoArgByName(mediaItemBuilder, "build")
            ?: throw IllegalStateException("MediaItem build failed for ${sourceUri}")
    }

    private fun startTransformation(transformer: Any, mediaItem: Any, outputPath: String): Boolean {
        val methods = transformer::class.java.methods
            .filter { (it.name == "start" || it.name == "startTransformation") && it.parameterTypes.size == 2 }

        for (method in methods) {
            val firstParam = method.parameterTypes[0]
            val secondParam = method.parameterTypes[1]
            if (!secondParam.isAssignableFrom(String::class.java)) continue
            if (!firstParam.isAssignableFrom(mediaItem::class.java)) continue

            runCatching {
                method.invoke(transformer, mediaItem, outputPath)
            }.onSuccess {
                return true
            }
        }
        return false
    }

    private fun cancelTransformation(transformer: Any) {
        val cancelMethod = transformer::class.java.methods.firstOrNull {
            (it.name == "cancel" || it.name == "cancelTransformation") && it.parameterTypes.isEmpty()
        } ?: return
        runCatching { cancelMethod.invoke(transformer) }
    }

    private fun invokeSingleArgByName(receiver: Any, methodName: String, arg: Any): Boolean {
        val method = receiver::class.java.methods.firstOrNull {
            it.name == methodName && it.parameterTypes.size == 1 &&
                    it.parameterTypes[0].isAssignableFrom(arg::class.java)
        } ?: return false

        return runCatching {
            method.invoke(receiver, arg)
            true
        }.getOrDefault(false)
    }

    private fun invokeNoArgByName(receiver: Any, methodName: String): Any? {
        val method = receiver::class.java.methods.firstOrNull {
            it.name == methodName && it.parameterTypes.isEmpty()
        } ?: return null
        return runCatching { method.invoke(receiver) }.getOrNull()
    }

    private fun completedByFile(outFile: File): Boolean {
        return outFile.exists() && outFile.length() > 0L
    }

    private fun findAudioTrackIndex(@Suppress("UNUSED_PARAMETER") extractor: Any): Int? {
        // Retained as a compatibility stub; no longer used after Media3 Transformer migration.
        return null
    }

    private fun resolveUri(audioRef: String): Uri {
        val parsed = audioRef.toUri()
        return if (parsed.scheme.isNullOrBlank()) {
            Uri.fromFile(File(audioRef))
        } else {
            parsed
        }
    }

    private fun guessMimeType(uri: Uri, rawRef: String): String {
        val raw = (uri.lastPathSegment ?: rawRef).lowercase()
        return when {
            raw.endsWith(".m4a") || raw.endsWith(".mp4") -> "audio/mp4"
            raw.endsWith(".aac") -> "audio/aac"
            raw.endsWith(".mp3") -> "audio/mpeg"
            raw.endsWith(".wav") -> "audio/wav"
            raw.endsWith(".flac") -> "audio/flac"
            raw.endsWith(".ogg") -> "audio/ogg"
            else -> "application/octet-stream"
        }
    }

    private fun isAllowedFallbackMime(mimeType: String): Boolean {
        // Keep fallback conservative to avoid 400 invalid argument from unsupported containers/codecs.
        return mimeType == "audio/mp4" || mimeType == "audio/mpeg" || mimeType == "audio/wav"
    }

    // google-genai 不同版本的 embeddings 返回结构可能不同，这里做兼容解析。
    private fun extractEmbeddingValues(raw: Any?): List<Float>? {
        if (raw == null) return null

        if (raw is Optional<*>) {
            Log.d(LOG_TAG, "embedding parse path=optional, present=${raw.isPresent}")
            return if (raw.isPresent) extractEmbeddingValues(raw.get()) else null
        }

        val direct = toFloatList(raw)
        if (direct != null) {
            Log.d(LOG_TAG, "embedding parse path=direct")
            return direct
        }

        if (raw is List<*> && raw.isNotEmpty()) {
            Log.d(LOG_TAG, "embedding parse path=list-first")
            val first = raw.firstOrNull()
            val fromFirst = toFloatList(first)
            if (fromFirst != null) return fromFirst
            return extractEmbeddingValues(first)
        }

        val extracted = runCatching {
            val method = raw::class.java.methods.firstOrNull {
                (it.name == "values" || it.name == "getValues" || it.name == "embedding" || it.name == "getEmbedding") &&
                        it.parameterTypes.isEmpty()
            } ?: return@runCatching null
            val invoked = method.invoke(raw)
            Log.d(LOG_TAG, "embedding parse path=reflection, method=${method.name}, type=${invoked?.javaClass?.name ?: "null"}")
            invoked
        }.getOrNull()

        if (extracted != null) {
            val byDirect = toFloatList(extracted)
            if (byDirect != null) return byDirect
            return extractEmbeddingValues(extracted)
        }

        return null
    }

    private fun toFloatList(value: Any?): List<Float>? {
        return when (value) {
            null -> null
            is FloatArray -> value.toList()
            is DoubleArray -> value.map { it.toFloat() }
            is List<*> -> value.mapNotNull { (it as? Number)?.toFloat() }
                .takeIf { it.isNotEmpty() }
            is Iterable<*> -> value.mapNotNull { (it as? Number)?.toFloat() }
                .takeIf { it.isNotEmpty() }
            else -> null
        }
    }


    private fun preview(text: String, max: Int = 220): String {
        return if (text.length <= max) text else text.take(max) + "..."
    }
}

package com.bbblllllocck.canned_emotions.core.database.geminiRequestCall

import android.content.Context
import android.net.Uri
import android.util.Log
import androidx.core.net.toUri
import com.bbblllllocck.canned_emotions.core.api.AppContextProvider
import com.google.genai.types.Blob
import com.google.genai.types.Content
import com.google.genai.types.EmbedContentConfig
import com.google.genai.types.Part
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.sync.Semaphore
import kotlinx.coroutines.sync.withPermit
import kotlinx.coroutines.withContext
import java.io.File

private const val LOG_TAG = "EmbeddingCall"
private const val MAX_AUDIO_DURATION_MS = 80_000L
private const val TRANSCODE_TIMEOUT_MS = 20_000L

private val apiSemaphore = Semaphore(2)

private class PreparedAudio(
    val bytes: ByteArray,
    val mimeType: String,
    val tempFile: File? = null
)

object EmbeddingCall {

    /**
     * 唯一公开入口：传入数据库中的 filePath（content Uri 或绝对路径），返回 embedding 向量。
     */
    suspend fun process(audioRef: String, context: Context = AppContextProvider.get()): List<Float> {
        Log.i(LOG_TAG, "process start, ref=$audioRef")

        val prepared = withContext(Dispatchers.IO) {
            prepareAudio(context, audioRef)
        }

        return try {
            apiSemaphore.withPermit {
                ClientManager.executeWithRetry { healthyClient ->
                    Log.d(LOG_TAG, "embed request start, mime=${prepared.mimeType}, bytes=${prepared.bytes.size}")

                    val audioPart = Part.builder()
                        .inlineData(
                            Blob.builder()
                                .data(prepared.bytes)
                                .mimeType(prepared.mimeType)
                                .build()
                        )
                        .build()

                    val content = Content.builder()
                        .parts(listOf(audioPart))
                        .build()

                    val config = EmbedContentConfig.builder()
                        .outputDimensionality(768)
                        .taskType("RETRIEVAL_DOCUMENT")
                        .build()

                    val response = healthyClient.models.embedContent(
                        "gemini-embedding-2-preview",
                        content,
                        config
                    )

                    val rawEmbeddings = response.embeddings()
                    Log.d(LOG_TAG, "embeddings raw type=${rawEmbeddings?.javaClass?.name ?: "null"}")

                    EmbeddingValueParser.extract(rawEmbeddings, LOG_TAG)
                        ?: throw IllegalStateException(
                            "Gemini embedding empty, mime=${prepared.mimeType}, bytes=${prepared.bytes.size}, " +
                                "rawType=${rawEmbeddings?.javaClass?.name ?: "null"}, " +
                                "responseType=${response.javaClass.name}, responsePreview=${preview(response.toString())}"
                        )
                }
            }
        } finally {
            Log.d(LOG_TAG, "process end, tempDeleted=${prepared.tempFile != null}")
            prepared.tempFile?.delete()
        }
    }

    private fun prepareAudio(context: Context, audioRef: String): PreparedAudio {
        val sourceUri = resolveUri(audioRef)
        Log.d(LOG_TAG, "prepareAudio source=$sourceUri")

        var transcodeError: Throwable? = null
        val aacFile = runCatching {
            Media3AudioTranscoder.transcodeToAacClip(
                context = context,
                sourceUri = sourceUri,
                maxDurationMs = MAX_AUDIO_DURATION_MS,
                timeoutMs = TRANSCODE_TIMEOUT_MS,
                logTag = LOG_TAG
            )
        }.onFailure {
            transcodeError = it
        }.getOrNull()

        if (aacFile != null && aacFile.exists()) {
            Log.d(LOG_TAG, "audio transcode success, upload mime=audio/mp4")
            return PreparedAudio(
                bytes = aacFile.readBytes(),
                mimeType = "audio/mp4",
                tempFile = aacFile
            )
        }

        val fallbackBytes = context.contentResolver.openInputStream(sourceUri)?.use { it.readBytes() }
            ?: throw IllegalStateException("无法读取音频: $audioRef")

        if (transcodeError != null) {
            Log.w(LOG_TAG, "audio transcode failed, fallback to source bytes", transcodeError)
        } else {
            Log.w(LOG_TAG, "audio transcode skipped, fallback to source bytes")
        }

        val fallbackMime = guessMimeType(sourceUri, audioRef)
        Log.d(LOG_TAG, "fallback mime=$fallbackMime")

        if (!isAllowedFallbackMime(fallbackMime)) {
            throw IllegalStateException(
                "AAC transcode failed and fallback mime is unsupported: $fallbackMime, ref=$audioRef"
            )
        }

        return PreparedAudio(bytes = fallbackBytes, mimeType = fallbackMime)
    }

    private fun resolveUri(audioRef: String): Uri {
        val parsed = audioRef.toUri()
        return if (parsed.scheme.isNullOrBlank()) Uri.fromFile(File(audioRef)) else parsed
    }

    private fun guessMimeType(uri: Uri, rawRef: String): String {
        val raw = (uri.lastPathSegment ?: rawRef).lowercase()
        return when {
            raw.endsWith(".m4a") || raw.endsWith(".mp4") -> "audio/mp4"
            raw.endsWith(".aac") -> "audio/aac"
            raw.endsWith(".mp3") -> "audio/mpeg"
            raw.endsWith(".wav") -> "audio/wav"
            raw.endsWith(".flac") -> "audio/flac"
            raw.endsWith(".ogg") -> "audio/ogg"
            else -> "application/octet-stream"
        }
    }

    private fun isAllowedFallbackMime(mimeType: String): Boolean {
        return mimeType == "audio/mp4" || mimeType == "audio/mpeg" || mimeType == "audio/wav"
    }

    private fun preview(text: String, max: Int = 220): String {
        return if (text.length <= max) text else text.take(max) + "..."
    }
}

package com.bbblllllocck.canned_emotions.core.database.geminiRequestCall

import com.bbblllllocck.canned_emotions.core.api.APIManagement
import com.bbblllllocck.canned_emotions.core.api.ApiCredential
import com.google.genai.Client

/** Binds one configured Gemini client with its source credential. */
data class ManagedGeminiClient(
    val credential: ApiCredential,
    val client: Client
)

private data class ClientSlot(
    val apiKey: String,
    val client: Client
)

class GeminiClientManager(
    private val apiManagement: APIManagement
) : AutoCloseable {

    private val clientSlots = mutableMapOf<String, ClientSlot>()
    private var roundRobinIndex = 0

    fun getAll(): List<ManagedGeminiClient> {
        val credentials = apiManagement.getAll()
        if (credentials.isEmpty()) return emptyList()

        synchronized(this) {
            val validIds = credentials.map { it.id }.toSet()

            // Close removed credentials' clients to avoid leaking resources.
            val removedIds = clientSlots.keys.filterNot { it in validIds }
            removedIds.forEach { id ->
                clientSlots.remove(id)?.client?.close()
            }

            credentials.forEach { credential ->
                val cached = clientSlots[credential.id]
                if (cached == null || cached.apiKey != credential.apiKey) {
                    cached?.client?.close()
                    clientSlots[credential.id] = ClientSlot(
                        apiKey = credential.apiKey,
                        client = Client.builder().apiKey(credential.apiKey).build()
                    )
                }
            }

            return credentials.mapNotNull { credential ->
                val slot = clientSlots[credential.id] ?: return@mapNotNull null
                ManagedGeminiClient(credential = credential, client = slot.client)
            }
        }
    }

    fun next(): ManagedGeminiClient? {
        val clients = getAll()
        if (clients.isEmpty()) return null

        synchronized(this) {
            if (roundRobinIndex >= clients.size) {
                roundRobinIndex = 0
            }
            val selected = clients[roundRobinIndex]
            roundRobinIndex = (roundRobinIndex + 1) % clients.size
            return selected
        }
    }

    override fun close() {
        synchronized(this) {
            clientSlots.values.forEach { it.client.close() }
            clientSlots.clear()
            roundRobinIndex = 0
        }
    }
}
